import React from 'react';

const GlicoLogo = ({ size = 'medium', className = '' }) => {
  const sizeClasses = {
    small: 'h-8',
    medium: 'h-12',
    large: 'h-16'
  };

  return (
    <div className={`flex items-center ${sizeClasses[size]} ${className}`}>
      {/* Three Diagonal Stripes */}
      <div className="flex mr-3">
        <div className="w-1 h-full bg-red-500 transform rotate-12 mr-1"></div>
        <div className="w-1 h-full bg-cyan-400 transform rotate-12 mr-1"></div>
        <div className="w-1 h-full bg-blue-700 transform rotate-12"></div>
      </div>

      {/* GLICO Text */}
      <div className="flex items-center">
        <div className="text-red-500 font-bold tracking-wide">
          <span className="inline-block bg-red-500 text-white px-1 py-0.5 mr-0.5" style={{ clipPath: 'polygon(0 0, 100% 0, 100% 100%, 20% 100%, 0 80%)' }}>G</span>
          <span className="inline-block bg-red-500 text-white px-1 py-0.5 mr-0.5">L</span>
          <span className="inline-block bg-red-500 text-white px-1 py-0.5 mr-0.5">I</span>
          <span className="inline-block bg-red-500 text-white px-1 py-0.5 mr-0.5">C</span>
          <span className="inline-block bg-red-500 text-white px-1 py-0.5 mr-1 relative">
            O
            <span className="absolute -top-1 -right-1 text-xs text-black">®</span>
          </span>
        </div>

        {/* LIFE Text */}
        <div className="text-blue-700 font-bold text-sm ml-1">
          LIFE
        </div>
      </div>
    </div>
  );
};

export default GlicoLogo;
